import heapq
import math
from collections import defaultdict


def _coord_tuple(c):
    if isinstance(c, dict):
        c = c.get('coords', c.get('coord', c.get('pos', c)))
    return (float(c[0]), float(c[1]))


def _key(c, ndigits=3):
    c = _coord_tuple(c)
    return (round(c[0], ndigits), round(c[1], ndigits))


def _dist(a, b):
    ax, ay = _coord_tuple(a)
    bx, by = _coord_tuple(b)
    return math.hypot(ax - bx, ay - by)


class GraphUtilityPlanner:
    """Deterministic sparse-graph utility/frontier planner for ExplorationEnv."""

    DEFAULTS = {
        'alpha': 1.0,
        'beta': 1.0,
        'utility_power': 1.0,
        'visited_penalty': 0.0,
        'mode': 'ratio',
        'lambda_dist': 0.02,
        'prefer_unvisited': 0.0,
        'nearest_fallback': True,
        'min_gain': 1e-9,
        # Optional near-completion behavior. Kept inactive by default for backward compatibility.
        'endgame_threshold': 1.1,
        'endgame_frontier_weight': 1.0,
        'endgame_dist_weight': 0.25,
        'endgame_utility_weight': 0.05,
        'endgame_allow_zero_utility': True,
        'endgame_unvisited_bonus': 0.0,
    }

    def __init__(self, alpha=1.0, beta=1.0, utility_power=1.0, visited_penalty=0.0,
                 mode='ratio', lambda_dist=0.02, prefer_unvisited=0.0,
                 nearest_fallback=True, min_gain=1e-9,
                 endgame_threshold=1.1, endgame_frontier_weight=1.0,
                 endgame_dist_weight=0.25, endgame_utility_weight=0.05,
                 endgame_allow_zero_utility=True, endgame_unvisited_bonus=0.0):
        self.alpha = float(alpha)
        self.beta = float(beta)
        self.utility_power = float(utility_power)
        self.visited_penalty = float(visited_penalty)
        self.mode = str(mode)
        self.lambda_dist = float(lambda_dist)
        self.prefer_unvisited = float(prefer_unvisited)
        self.nearest_fallback = bool(nearest_fallback)
        self.min_gain = float(min_gain)
        self.endgame_threshold = float(endgame_threshold)
        self.endgame_frontier_weight = float(endgame_frontier_weight)
        self.endgame_dist_weight = float(endgame_dist_weight)
        self.endgame_utility_weight = float(endgame_utility_weight)
        self.endgame_allow_zero_utility = bool(endgame_allow_zero_utility)
        self.endgame_unvisited_bonus = float(endgame_unvisited_bonus)

    @classmethod
    def from_config(cls, cfg):
        d = dict(cls.DEFAULTS)
        if cfg:
            d.update({k: v for k, v in cfg.items() if k in d})
        return cls(**d)

    def to_config(self):
        return {k: getattr(self, k) for k in self.DEFAULTS.keys()}

    def _build_graph(self, obs):
        nodes = obs.get('nodes', []) or []
        graph = defaultdict(list)
        node_info = {}
        coord_by_key = {}
        for n in nodes:
            if not isinstance(n, dict) or 'coords' not in n:
                continue
            c = _coord_tuple(n['coords'])
            k = _key(c)
            coord_by_key[k] = c
            node_info[k] = n
        for n in nodes:
            if not isinstance(n, dict) or 'coords' not in n:
                continue
            k = _key(n['coords'])
            kc = coord_by_key.get(k, _coord_tuple(n['coords']))
            for nb in n.get('neighbors', []) or []:
                nk = _key(nb)
                nc = coord_by_key.get(nk, _coord_tuple(nb))
                coord_by_key.setdefault(nk, nc)
                w = _dist(kc, nc)
                graph[k].append((nk, w))
                graph[nk].append((k, w))
        return graph, node_info, coord_by_key

    def _dijkstra(self, graph, start_key):
        pq = [(0.0, start_key)]
        dist = {start_key: 0.0}
        prev = {}
        while pq:
            d, u = heapq.heappop(pq)
            if d != dist.get(u):
                continue
            for v, w in graph.get(u, []):
                nd = d + w
                if nd < dist.get(v, 1e30):
                    dist[v] = nd
                    prev[v] = u
                    heapq.heappush(pq, (nd, v))
        return dist, prev

    def _first_step(self, start_key, target_key, prev, coord_by_key, legal_neighbors):
        if target_key == start_key:
            return None
        cur = target_key
        seen = 0
        while prev.get(cur) is not None and prev[cur] != start_key and seen < 10000:
            cur = prev[cur]
            seen += 1
        cand = coord_by_key.get(cur)
        if cand is None:
            return None
        ck = _key(cand)
        for nb in legal_neighbors:
            if _key(nb) == ck:
                return _coord_tuple(nb)
        # Safety: env.step requires a neighboring node; fall back to closest legal neighbor.
        if legal_neighbors:
            return min((_coord_tuple(nb) for nb in legal_neighbors), key=lambda x: _dist(x, cand))
        return None

    def _candidate_score(self, util, d, visited):
        u = max(float(util), 0.0)
        if u <= 0:
            return -1e30
        if visited:
            u *= max(0.0, 1.0 - self.visited_penalty)
        else:
            u *= (1.0 + self.prefer_unvisited)
        up = max(u, self.min_gain) ** self.utility_power
        dd = max(float(d), 0.0)
        if self.mode == 'linear':
            return up - self.lambda_dist * dd
        if self.mode == 'highutil':
            return up * 1000.0 - dd
        if self.mode == 'nearest':
            return -dd + self.lambda_dist * up
        return up / ((dd + self.alpha) ** self.beta)

    def _nearest_frontier_dist(self, c, frontiers):
        if not frontiers:
            return 1e6
        cx, cy = _coord_tuple(c)
        best = 1e30
        # Frontiers can be numerous; a full scan is still cheap compared with env raycasting.
        for f in frontiers:
            fx, fy = _coord_tuple(f)
            v = (cx - fx) * (cx - fx) + (cy - fy) * (cy - fy)
            if v < best:
                best = v
        return math.sqrt(best)

    def _select_endgame_target(self, obs, dist, node_info, coord_by_key, start_key):
        frontiers = obs.get('frontiers', []) or []
        if not frontiers:
            return None, -1e30
        best_key, best_score = None, -1e30
        for k, d in dist.items():
            if k == start_key or k not in coord_by_key:
                continue
            info = node_info.get(k, {})
            util = float(info.get('utility', 0.0)) if isinstance(info, dict) else 0.0
            if (not self.endgame_allow_zero_utility) and util <= 0:
                continue
            visited = bool(info.get('visited', False)) if isinstance(info, dict) else False
            fd = self._nearest_frontier_dist(coord_by_key[k], frontiers)
            score = (-self.endgame_frontier_weight * fd
                     -self.endgame_dist_weight * float(d)
                     +self.endgame_utility_weight * util)
            if not visited:
                score += self.endgame_unvisited_bonus
            if score > best_score:
                best_key, best_score = k, score
        return best_key, best_score

    def select_waypoint(self, obs):
        legal_neighbors = obs.get('neighbors', []) or []
        if not legal_neighbors:
            return None
        graph, node_info, coord_by_key = self._build_graph(obs)
        robot = _coord_tuple(obs.get('robot_pos', legal_neighbors[0]))
        if coord_by_key:
            start_key = min(coord_by_key.keys(), key=lambda k: _dist(coord_by_key[k], robot))
        else:
            return _coord_tuple(legal_neighbors[0])
        dist, prev = self._dijkstra(graph, start_key)
        if not dist:
            return min((_coord_tuple(nb) for nb in legal_neighbors), key=lambda x: _dist(x, robot))

        explored_rate = float(obs.get('explored_rate', 0.0))
        if explored_rate >= self.endgame_threshold:
            ek, es = self._select_endgame_target(obs, dist, node_info, coord_by_key, start_key)
            if ek is not None:
                step = self._first_step(start_key, ek, prev, coord_by_key, legal_neighbors)
                if step is not None:
                    return step

        best_key, best_score = None, -1e30
        nearest_pos_key, nearest_pos_dist = None, 1e30
        for k, d in dist.items():
            info = node_info.get(k)
            if not isinstance(info, dict):
                continue
            util = float(info.get('utility', 0.0))
            visited = bool(info.get('visited', False))
            if util > 0 and d < nearest_pos_dist and k != start_key:
                nearest_pos_key, nearest_pos_dist = k, d
            score = self._candidate_score(util, d, visited)
            if k == start_key:
                score -= 1e-6
            if score > best_score:
                best_key, best_score = k, score
        if (best_key is None or best_score <= -1e20) and self.nearest_fallback:
            best_key = nearest_pos_key
        if best_key is None:
            # Last-resort motion can occasionally reveal a sliver when utilities have vanished.
            return min((_coord_tuple(nb) for nb in legal_neighbors), key=lambda x: _dist(x, robot))
        step = self._first_step(start_key, best_key, prev, coord_by_key, legal_neighbors)
        if step is None:
            return min((_coord_tuple(nb) for nb in legal_neighbors), key=lambda x: _dist(x, coord_by_key.get(best_key, robot)))
        return step


class TypeAdaptivePlanner:
    def __init__(self, cfg):
        self.cfg = cfg or {}
        self.default_cfg = {k: v for k, v in self.cfg.items() if k != 'type_configs'}
        self.type_configs = self.cfg.get('type_configs', {}) if isinstance(self.cfg, dict) else {}

    def planner_for_type(self, env_type):
        cfg = dict(self.default_cfg)
        if env_type in self.type_configs:
            cfg.update(self.type_configs[env_type])
        return GraphUtilityPlanner.from_config(cfg)
